import redis
import ssl
import os
from typing import Optional, Union
from redis.cluster import RedisCluster

class SecureRedisClient:
    def __init__(self, redis_nodes: list, use_ssl: bool = True, password: Optional[str] = None):
        self.use_ssl = use_ssl
        self.password = password
        self.redis_nodes = redis_nodes
        self.client = None
        self._connect()
    
    def _connect(self):
        try:
            if self.use_ssl:
                # Create SSL context for secure connection
                ssl_context = ssl.create_default_context()
                ssl_context.check_hostname = True
                ssl_context.verify_mode = ssl.CERT_REQUIRED
                
                # Connect to Redis cluster with SSL
                self.client = RedisCluster(
                    startup_nodes=[redis.Node(node['host'], node['port']) for node in self.redis_nodes],
                    ssl=True,
                    ssl_context=ssl_context,
                    password=self.password,
                    decode_responses=True,
                    skip_full_coverage_check=True
                )
            else:
                # Non-SSL connection (not recommended for production)
                self.client = RedisCluster(
                    startup_nodes=[redis.Node(node['host'], node['port']) for node in self.redis_nodes],
                    password=self.password,
                    decode_responses=True,
                    skip_full_coverage_check=True
                )
        except Exception as e:
            raise Exception(f"Failed to connect to Redis cluster: {str(e)}")
    
    def set_with_ttl(self, key: str, value: Union[str, bytes], ttl_seconds: int) -> bool:
        try:
            if isinstance(value, str):
                self.client.setex(key, ttl_seconds, value)
            else:
                self.client.setex(key, ttl_seconds, value)
            return True
        except Exception as e:
            print(f"Error setting key {key}: {str(e)}")
            return False
    
    def get(self, key: str) -> Optional[Union[str, bytes]]:
        try:
            return self.client.get(key)
        except Exception as e:
            print(f"Error getting key {key}: {str(e)}")
            return None
    
    def delete(self, key: str) -> bool:
        try:
            return self.client.delete(key) > 0
        except Exception as e:
            print(f"Error deleting key {key}: {str(e)}")
            return False
    
    def set_session_token(self, user_id: str, token: str, ttl_seconds: int = 3600) -> bool:
        key = f"session:{user_id}"
        return self.set_with_ttl(key, token, ttl_seconds)
    
    def get_session_token(self, user_id: str) -> Optional[str]:
        key = f"session:{user_id}"
        return self.get(key)
    
    def set_api_key(self, user_id: str, api_key: str, ttl_seconds: int = 86400) -> bool:
        key = f"api_key:{user_id}"
        return self.set_with_ttl(key, api_key, ttl_seconds)
    
    def get_api_key(self, user_id: str) -> Optional[str]:
        key = f"api_key:{user_id}"
        return self.get(key)
    
    def close(self):
        if self.client:
            self.client.close()

